import styled from "styled-components";

export const Item = styled.button`

    font-size: 1.5em;
    font-weight: 500;
    box-sizing: border-box;
    transition: .5s;
    opacity: 1;


    :hover{
        cursor: pointer;
        background-color: #fec453;
        text-shadow: 0px 0px 2px black;
    }
`;
